"use strict";function calculateStatsPerFile(t){const r={errorCount:0,fatalErrorCount:0,warningCount:0,fixableErrorCount:0,fixableWarningCount:0};for(let a=0;a<t.length;a++){const n=t[a];n.fatal||2===n.severity?(r.errorCount++,n.fatal&&r.fatalErrorCount++,n.fix&&r.fixableErrorCount++):(r.warningCount++,n.fix&&r.fixableWarningCount++)}return r}module.exports={calculateStatsPerFile:calculateStatsPerFile};